results.system_sql:
SELECT s.name, AVG(sc.marks) AS avg_marks
FROM students s
JOIN scores sc ON s.id = sc.student_id;

results.baseline_sql:
SELECT * FROM students
ORDER BY GPA DESC
LIMIT 1;

SELECT s.student_name
FROM students s
WHERE s.average_marks > (SELECT AVG(s2.average_marks) FROM students s2);
